const listBlock = (data, list) => {
    for (const prop in data.nameperiods){
        list.push([data.nameperiods[prop]])
    }
    data.periodsdesc.period1.map((desc) => {
        list[0].push(desc)
        return list
    })
    data.periodsdesc.period2.map((desc) => {
        list[1].push(desc)
        return list
    })
    data.periodsdesc.period3.map((desc) => {
        list[2].push(desc)
        return list
    })

    return list
};
export default listBlock;
