import React from 'react';
//import Typography from '@material-ui/core/Typography';
//import { makeStyles } from '@material-ui/core/styles';
//import Paper from '@material-ui/core/Paper';
import Button from '@material-ui/core/Button';
//import Grid from '@material-ui/core/Grid';
import TextField from '@material-ui/core/TextField';
import FormControl from '@material-ui/core/FormControl';
import FormControlLabel from '@material-ui/core/FormControlLabel';
import Checkbox from '@material-ui/core/Checkbox';


const CalculateField=(props)=>{
    //const value=props.value;
    const err=props.err;
    const check=props.check
    const checkB = props.checkB
    const title=props.title
    const label=props.label;
    const order=props.order;
    
    return(
        <FormControl  noValidate autoComplete="off">
            <TextField id={`outlined-basic${props.id}`}
                error={err}
                label={label}
                variant="outlined"
                onChange={props.onChange} />
            {/*{title.map((tabletitle, i) => (
                <>
                {i<=3?i===0? 
                    <FormControlLabel
                    control={<Checkbox checked={check.all} onChange={checkB} name="all" />}
                    label='Всі'
                />:<FormControlLabel
                            control={<Checkbox checked={`{check.all}`}  onChange={checkB} name={`complex${i}`} />}
                        label={tabletitle}
                />:<></>}
                </>
            ))}*/}

            <FormControlLabel
                control={<Checkbox checked={check.period1} onChange={checkB} name="period1"  />}
                label={title.period1}
            />
            <FormControlLabel
                control={<Checkbox checked={check.period2} onChange={checkB} name="period2" />}
                label={title.period2}
            />
            <FormControlLabel
                control={<Checkbox checked={check.period3} onChange={checkB} name="period3" />}
                label={title.period3}
            />
            
            <Button size="large" className={order} onClick={props.onClick}>Розрахувати</Button>
        </FormControl >
    )
}
export default CalculateField;