import React from 'react';
import Container from '@material-ui/core/Container';
import { makeStyles } from '@material-ui/core/styles';


import ModalOrder from './ModalOrder';
import Data from '../data/data.json';
import ContentSection from './ContentSection';
import './topmenu.css';

let payload = {};
const useStyles = makeStyles((theme) => ({
    root:{
        paddingLeft: '1rem',
    },
    textContainer:{
        padding:'1rem',
    },
    listIcon:{
        minWidth: '19px',
    },
    advTitle:{
        color:'#00823c',
        paddingTop:0,
        paddingBottom:'8px',
    },
    titleBox:{
        width: 'inherit',
        position: 'relative',
    },
    boxPosition:{
        color: '#ffff',
        background: 'rgba(0, 130, 90, 0.7)',
        position: 'absolute',
        bottom: '1rem',
        width: 'inherit',
    },
    wrapTable: {
        marginBottom: '2rem',
    },
    wrap: {
        paddingTop: '8rem',
    },
}));


const LandingCard =(props)=>{
    const [open, setOpen] = React.useState(false);
    const [modal, setModal] = React.useState(0);
    
    const handleClickOpen = (e) => {
        const idx = e.currentTarget.id;
        payload=Data[idx-1];                      
        setOpen(true);
        setModal(idx);
    };
    const handleClose = () => {
        setOpen(false);
    };
    const classes = useStyles();
    const data=Data[0].crop;
    return(
        <Container  className={classes.wrap}>
            {data.map((data)=>( 
                <ContentSection  
                    data={data}
                    handleClickOpen={handleClickOpen}/>   
            ))}
            <ModalOrder open={open}
                        id={modal}
                        onClose={handleClose}
                        content={payload}
                        />            
         </Container>
    );

}
export default LandingCard;