import React from 'react';
import { makeStyles } from '@material-ui/core/styles';
import AppBar from '@material-ui/core/AppBar';
import Paper from '@material-ui/core/Paper';
import Tabs from '@material-ui/core/Tabs';
import Tab from '@material-ui/core/Tab';


const useStyles = makeStyles((theme)=>({
    root: {
        flexGrow: 1,
        [theme.breakpoints.down('xs')]: {
            visibility: 'hidden',
        },
    },
    colorPrimary: {
        marginTop: '5rem',
        position: 'fixed',
        background: 'linear-gradient(#555, #222)',
        boxShadow: '0 1px 1px #777, 0 1px 0 #666 inset',
    },
}));

export default function TopMenu(props) {
    const classes = useStyles();
    const [value, setValue] = React.useState(0);

    const handleChange = (event, newValue) => {
        setValue(newValue);
    };
    const handleScroll = (e) => {
        const idx = e.currentTarget.id;
        const section = (document.getElementById(`section${idx}`).offsetTop) - 120;
        window.scrollTo({
            top: section,
            behavior: "smooth"
        })
    }

    return (
        <Paper className={classes.root}>
            <AppBar position="static" className={classes.colorPrimary}>
            <Tabs
                value={value}
                onChange={handleChange}
                centered
                selected={false}
            >
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="1" onClick={handleScroll} label="Ярі та озимі зернові культури" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="2" onClick={handleScroll} label="Соняшник" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="3" onClick={handleScroll} label="Кукурудза" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="4" onClick={handleScroll} label="Ярий та озимий ріпак" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="5" onClick={handleScroll} label="Соя" />
                    <Tab style={{ minWidth: 'auto', fontSize: '0.85rem' }} id="6" onClick={handleScroll} label="Цукровий буряк" />
            </Tabs>
            </AppBar>
        </Paper>
    );
}